
DELETE FROM U_DIS_TT WHERE SUBSTRING(DIT_GRUPPO,4,2) = 'A4' AND DIT_GRUPPO IN (SELECT PR.ART_CODPRI FROM U_ART_PR AS PR LEFT OUTER JOIN U_ART_AN AS AN ON PR.ART_CODPRI = AN.ART_CODPRI WHERE PR.ART_CODMAT = '008' AND AN.ART_TIPOG = '' AND AN.ART_TIPON <> '')
DELETE FROM U_DIS_DD WHERE SUBSTRING(DIS_GRUPPO,4,2) = 'A4' AND DIS_GRUPPO IN (SELECT PR.ART_CODPRI FROM U_ART_PR AS PR LEFT OUTER JOIN U_ART_AN AS AN ON PR.ART_CODPRI = AN.ART_CODPRI WHERE PR.ART_CODMAT = '008' AND AN.ART_TIPOG = '' AND AN.ART_TIPON <> '')

SELECT * FROM U_DIS_TT WHERE SUBSTRING(DIT_GRUPPO,4,2) = 'A4' AND DIT_GRUPPO IN (SELECT PR.ART_CODPRI FROM U_ART_PR AS PR LEFT OUTER JOIN U_ART_AN AS AN ON PR.ART_CODPRI = AN.ART_CODPRI WHERE PR.ART_CODMAT = '008' AND AN.ART_TIPOG = '' AND AN.ART_TIPON <> '')
SELECT * FROM U_DIS_DD WHERE SUBSTRING(DIS_GRUPPO,4,2) = 'A4' AND DIS_GRUPPO IN (SELECT PR.ART_CODPRI FROM U_ART_PR AS PR LEFT OUTER JOIN U_ART_AN AS AN ON PR.ART_CODPRI = AN.ART_CODPRI WHERE PR.ART_CODMAT = '008' AND AN.ART_TIPOG = '' AND AN.ART_TIPON <> '')
